@font-face {
  font-family: 'Inter Variable';
  src: url('Inter-roman.var.woff2') format('woff2');
  font-weight: 100 900;
  font-style: normal;
  font-display: swap;
}

body {
  font-family: 'Inter Variable', sans-serif;
  font-variation-settings: "wght" 450; /* Example: setting a specific weight */
}

h1 {
  font-variation-settings: "wght" 780, "slnt" -10; /* Example: multiple axes */
}
